class BiometricAuthService {
  final LocalAuthentication _localAuth = LocalAuthentication();
  static const String _sessionKeyPrefix = 'session_key_';
  static const String _encryptedCredentialsKey = 'encrypted_credentials';
  static const String _sessionTimestampKey = 'session_timestamp';
  static const String _biometricEnabledKey = 'biometric_enabled';
  static const int _sessionValidityHours = 24;

  Future<bool> canUseBiometric() async {
    try {
      final canCheckBiometrics = await _localAuth.canCheckBiometrics;
      if (!canCheckBiometrics) return false;

      final availableBiometrics = await _localAuth.getAvailableBiometrics();
      return availableBiometrics.isNotEmpty;
    } catch (e) {
      return false;
    }
  }

  Future<bool> authenticateWithBiometric() async {
