    final sessionTime = DateTime.fromMillisecondsSinceEpoch(timestamp);
    final now = DateTime.now();
    final difference = now.difference(sessionTime);
    
    if (difference.inHours > _sessionValidityHours) {
      await logout();
      return false;
    }
    
    final encryptedData = prefs.getString(_encryptedCredentialsKey);
    return encryptedData != null;
  }

  Future<String?> getSessionKey() async {
    final prefs = await SharedPreferences.getInstance();
    final encryptedData = prefs.getString(_encryptedCredentialsKey);
    
    if (encryptedData == null) return null;
    
    final parts = encryptedData.split(':');
    if (parts.length != 2) return null;
    
    final username = parts[0];
    return prefs.getString(_sessionKeyPrefix + username);
  }

  Future<void> logout() async {
    final prefs = await SharedPreferences.getInstance();
    final keys = prefs.getKeys();
    
    for (final key in keys) {
      if (key.startsWith(_sessionKeyPrefix) || 
          key == _encryptedCredentialsKey ||
          key == _sessionTimestampKey ||
          key == _biometricEnabledKey) {
        await prefs.remove(key);
      }
